// // This module captures the value of the input D on the falling edge of the clk signal and outputs it as q, while the complementary output qBar is generated using a NOT gate.
module top_module(q, qBar, D, clk);input D, clk;
	output q, qBar;
	reg q;
	not n1 (qBar, q);
		always@ (posedge clk)
		begin
			q <= D;
		end
endmodule
